// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Basic input validation to prevent obvious shell injection
	if strings.ContainsAny(loadBalancerName, "`$\n\r\t|>") || strings.ContainsAny(outputFile, "`$\n\r\t|>") {
		return "", fmt.Errorf("invalid characters in input parameters")
	}

	// Create separate commands for aliyun and jq
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Set up pipe from aliyun command to jq command
	aliyunOutput, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun command: %w", err)
	}

	jqCmd.Stdin = aliyunOutput

	// Execute aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Get jq output
	outputBytes, err := jqCmd.Output()
	if err != nil {
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Write the formatted output to the specified file
	if err := writeFile(outputFile, outputBytes); err != nil {
		return "", fmt.Errorf("failed to write output to file: %w", err)
	}

	return string(outputBytes), nil
}

// writeFile writes data to the specified file
func writeFile(filename string, data []byte) error {
	// Use safeWriteFile directly instead of shell command to avoid injection
	return safeWriteFile(filename, data)
}

// safeWriteFile is a safer alternative to write file without shell injection risk
func safeWriteFile(filename string, data []byte) error {
	return os.WriteFile(filename, data, 0644)
}

