package main

import (
	"fmt"
	"os/exec"
	"regexp"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate inputs using regex to prevent shell injection
	validNamePattern := regexp.MustCompile(`^[a-zA-Z0-9-_]+$`)
	if !validNamePattern.MatchString(loadBalancerName) {
		return "", fmt.Errorf("invalid loadBalancerName: contains illegal characters")
	}

	// For output file, we allow more characters but still exclude shell metacharacters
	if matched, _ := regexp.MatchString(`[;&|$`+"`"+`\n\r\t<>|]`, outputFile); matched {
		return "", fmt.Errorf("invalid outputFile: contains illegal characters")
	}

	// Create separate commands for each part of the pipeline
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Set up pipe between aliyunCmd and jqCmd
	stdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}
	jqCmd.Stdin = stdout

	// Execute aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Get output from jq
	jqOutput, err := jqCmd.Output()
	if err != nil {
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Write the output to the specified file
	if err := exec.Command("sh", "-c", fmt.Sprintf("echo '%s' > '%s'", string(jqOutput), outputFile)).Run(); err != nil {
		return "", fmt.Errorf("failed to write output to file: %w", err)
	}

	// Wait for aliyun command to finish
	if err := aliyunCmd.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	return string(jqOutput), nil
}

