package main

import (
	"fmt"
	"os"
	"os/exec"
)

func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the first command: aliyun slb DescribeLoadBalancers --LoadBalancerName NAME
	cmd1 := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the second command: jq '.LoadBalancers.LoadBalancer[]'
	cmd2 := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Set up pipe from cmd1 to cmd2
	stdout1, err := cmd1.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for first command: %w", err)
	}
	cmd2.Stdin = stdout1

	// Start the first command
	err = cmd1.Start()
	if err != nil {
		return "", fmt.Errorf("failed to start first command: %w", err)
	}

	// Create output file
	outputFileHandle, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file %s: %w", outputFile, err)
	}
	defer outputFileHandle.Close()

	// Set up cmd2 to write to the output file
	cmd2.Stdout = outputFileHandle

	// Run the second command
	err = cmd2.Run()
	if err != nil {
		return "", fmt.Errorf("failed to run second command: %w", err)
	}

	// Wait for the first command to finish
	err = cmd1.Wait()
	if err != nil {
		return "", fmt.Errorf("first command failed: %w", err)
	}

	result := fmt.Sprintf("SLB information exported to %s successfully", outputFile)
	return result, nil
}

func main() {
	// Example usage
	loadBalancerName := "my-slb-name"
	outputFile := "output.json"

	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Println(result)
}

