package main

import (
	"fmt"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Basic input validation to prevent obvious shell injection
	if strings.ContainsAny(loadBalancerName, "`$\n\r\t|>") || strings.ContainsAny(outputFile, "`$\n\r\t|>") {
		return "", fmt.Errorf("invalid characters in input parameters")
	}

	// Use separate commands instead of a shell pipeline to avoid shell injection
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Connect aliyunCmd's stdout to jqCmd's stdin
	jqCmd.Stdin, _ = aliyunCmd.StdoutPipe()

	// Set jqCmd's stdout to write to the output file
	file, err := exec.Command("sh", "-c", "cat > "+outputFile).StdinPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdin pipe for output redirection: %w", err)
	}

	// Capture the output of jq command before writing to file
	jqCmd.Stdout = file

	// Start both commands
	err = aliyunCmd.Start()
	if err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	err = jqCmd.Start()
	if err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for both commands to finish
	err = aliyunCmd.Wait()
	if err != nil {
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	err = jqCmd.Wait()
	if err != nil {
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Close the file pipe
	err = file.Close()
	if err != nil {
		return "", fmt.Errorf("failed to close file pipe: %w", err)
	}

	// Now read the file back to return its contents as the output string
	catCmd := exec.Command("cat", outputFile)
	outputBytes, err := catCmd.Output()
	if err != nil {
		return "", fmt.Errorf("failed to read output file: %w", err)
	}

	return string(outputBytes), nil
}

