	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Set up pipe between commands
	stdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}
	jqCmd.Stdin = stdout

	// Execute the first command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Get output from jq
	jqOutput, err := jqCmd.Output()
	if err != nil {
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Wait for the first command to finish
	if err := aliyunCmd.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Write the output to the specified file
	if err := writeFile(outputFile, jqOutput); err != nil {
		return "", fmt.Errorf("failed to write output to file: %w", err)
	}

	return string(jqOutput), nil
}

// isValidInput checks if the input contains only allowed characters
// Only alphanumeric characters, hyphens, underscores, and periods are allowed
func isValidInput(input string) bool {
	// Check for empty input
	if input == "" {
		return true // Allow empty string as this might be valid depending on use case
	}

	// Regular expression that matches only safe characters
	// Alphanumeric, hyphen, underscore, period, space
	matched, err := regexp.MatchString(`^[a-zA-Z0-9_\-\. ]+$`, input)
	if err != nil {
		return false
	}
	return matched
}

// writeFile writes data to the specified file
func writeFile(filename string, data []byte) error {
	return exec.Command("sh", "-c", fmt.Sprintf("cat > '%s'", filename)).Run()
}

