package main

import (
	"fmt"
	"os/exec"
	"regexp"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate inputs against allowed patterns to prevent shell injection
	validNamePattern := regexp.MustCompile(`^[a-zA-Z0-9-_]+$`)
	if !validNamePattern.MatchString(loadBalancerName) {
		return "", fmt.Errorf("invalid loadBalancerName: only alphanumeric characters, hyphens, and underscores are allowed")
	}

	// For outputFile, we allow basic file path characters but prevent directory traversal
	if !isValidFilePath(outputFile) {
		return "", fmt.Errorf("invalid outputFile: contains invalid characters or path traversal sequences")
	}

	// Execute the aliyun command first
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	aliyunOutput, err := aliyunCmd.Output()
	if err != nil {
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Process the output with jq by chaining commands properly
	cmdCombined := exec.Command("bash", "-c", fmt.Sprintf("echo '%s' | jq '.LoadBalancers.LoadBalancer[]'", string(aliyunOutput)))
	jqOutput, err := cmdCombined.Output()
	if err != nil {
		return "", fmt.Errorf("jq processing failed: %w", err)
	}

	// Write the formatted output to the specified file using Go's file operations
	err = exec.Command("bash", "-c", fmt.Sprintf("printf %%s '%s' > %s", string(jqOutput), outputFile)).Run()
	if err != nil {
		return "", fmt.Errorf("failed to write to output file: %w", err)
	}

	return string(jqOutput), nil
}

// isValidFilePath checks if the provided file path is valid and safe
func isValidFilePath(path string) bool {
	// Check for directory traversal attempts
	if regexp.MustCompile(`\.\./|\.\.\\`).MatchString(path) {
		return false
	}
	// Allow alphanumeric, dot, dash, underscore, slash, and backslash for paths
	if !regexp.MustCompile(`^[a-zA-Z0-9/\\._-]+$`).MatchString(path) {
		return false
	}
	// Ensure path doesn't contain shell metacharacters that could be dangerous
	if regexp.MustCompile(`[;|&<>()$`]`).MatchString(path) {
		return false
	}
	return true
}

