// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Basic input validation to prevent obvious shell injection
	if strings.ContainsAny(loadBalancerName, "`$\n\r\t|>;&") || strings.ContainsAny(outputFile, "`$\n\r\t|>;&") {
		return "", fmt.Errorf("invalid characters in input parameters")
	}

	// Use separate commands to avoid shell injection risks
	slbCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Connect slbCmd output to jqCmd input
	jqCmd.Stdin, _ = slbCmd.StdoutPipe()

	// Set up jqCmd to write directly to the output file
	file, err := createOutputFile(outputFile)
	if err != nil {
		return "", err
	}
	defer file.Close()
	jqCmd.Stdout = file

	// Start the jq command
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Run the aliyun command
	slbOutput, err := slbCmd.CombinedOutput()
	if err != nil {
		return string(slbOutput), fmt.Errorf("aliyun command failed: %w, output: %s", err, string(slbOutput))
	}

	// Wait for jq to finish processing
	if err := jqCmd.Wait(); err != nil {
		return string(slbOutput), fmt.Errorf("jq command failed: %w", err)
	}

	// Return the output from the first command in the pipeline
	return string(slbOutput), nil
}

// createOutputFile creates or truncates the output file
func createOutputFile(filename string) (*os.File, error) {
	return os.Create(filename)
}

