func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate inputs using regex to ensure they contain only safe characters
	validNameRegex := regexp.MustCompile(`^[a-zA-Z0-9-_]+$`)
	if !validNameRegex.MatchString(loadBalancerName) {
