package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate inputs to prevent command injection
	if !isValidInput(loadBalancerName) || !isValidInput(outputFile) {
		return "", fmt.Errorf("invalid characters in input parameters")
	}

	// Create commands separately to avoid shell injection
	slbCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Set up pipe between commands
	stdout, err := slbCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("error creating stdout pipe: %w", err)
	}
	jqCmd.Stdin = stdout

	// Run the first command
	if err := slbCmd.Start(); err != nil {
		return "", fmt.Errorf("error starting aliyun command: %w", err)
	}

	// Get output from jq
	jqOutput, err := jqCmd.Output()
	if err != nil {
		return "", fmt.Errorf("error executing jq command: %w", err)
	}

	// Wait for the first command to finish
	if err := slbCmd.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Write output to file
	if err := exec.Command("bash", "-c", fmt.Sprintf("echo '%s' > '%s'", strings.ReplaceAll(string(jqOutput), "'", "'\"'\"'"), outputFile)).Run(); err != nil {
		return "", fmt.Errorf("error writing to output file: %w", err)
	}

	return string(jqOutput), nil
}

// isValidInput validates that the input contains only allowed characters
// This allows alphanumeric characters, hyphens, underscores, and periods
func isValidInput(input string) bool {
	// Check for valid characters: alphanumeric, hyphen, underscore, period, space
	validPattern := regexp.MustCompile(`^[a-zA-Z0-9._\- ]+$`)

	// Also make sure the input doesn't contain directory traversal patterns
	if strings.Contains(input, "../") || strings.Contains(input, "..\\") {
		return false
	}

	return validPattern.MatchString(input)
}

