// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate inputs using regex to prevent shell injection
	if !isValidInput(loadBalancerName) {
		return "", fmt.Errorf("invalid loadBalancerName: contains disallowed characters")
	}
	if !isValidOutputFile(outputFile) {
		return "", fmt.Errorf("invalid outputFile: contains disallowed characters")
	}

	// Use exec.Command with individual arguments to avoid shell interpretation
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Set up pipe: aliyunCmd stdout -> jqCmd stdin
	stdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}
	jqCmd.Stdin = stdout

	// Execute the first command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Get jq output
	outputBytes, err := jqCmd.Output()
	if err != nil {
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Wait for aliyun command to finish
	if err := aliyunCmd.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Write output to file
	if err := writeFile(outputFile, outputBytes); err != nil {
		return "", fmt.Errorf("failed to write output to file: %w", err)
	}

	return string(outputBytes), nil
}

// isValidInput validates that the input string contains only allowed characters
// This prevents shell injection by allowing only alphanumeric characters, hyphens, underscores, and periods
func isValidInput(input string) bool {
	// Allow letters, numbers, hyphens, underscores, and periods
	matched, err := regexp.MatchString(`^[a-zA-Z0-9_.-]+$`, input)
	if err != nil {
		return false
	}
	return matched
}

// isValidOutputFile validates that the output file path is safe
// It checks for directory traversal and ensures the path contains only allowed characters
func isValidOutputFile(filepath string) bool {
	// Check if the filepath contains directory traversal attempts
	if strings.Contains(filepath, "../") || strings.Contains(filepath, "..\\") {
		return false
	}

	// Allow letters, numbers, hyphens, underscores, periods, forward slashes, and backslashes
	// Also allow colons for Windows paths
	matched, err := regexp.MatchString(`^[a-zA-Z0-9_./:\\-]+$`, filepath)
	if err != nil {
		return false
	}

	return matched
}

// writeFile writes the provided data to the specified file
func writeFile(filepath string, data []byte) error {
	return exec.Command("sh", "-c", fmt.Sprintf("printf %%s '%s' > '%s'", 
		strings.ReplaceAll(string(data), "'", "'\"'\"'"), // Escape single quotes properly
		filepath)).Run()
}

