// isValidInput checks if the input contains only safe characters
func isValidInput(input string) bool {
	// Allow alphanumeric characters, hyphens, underscores, and spaces
	// This pattern can be adjusted based on actual requirements
	matched, err := regexp.MatchString(`^[a-zA-Z0-9\-_. ]+$`, input)
	if err != nil {
