package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the command to query SLB information
	cmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Execute the command and get the output
	output, err := cmd.Output()
	if err != nil {
		return "", fmt.Errorf("failed to execute aliyun command: %w", err)
	}

	// Create a command to pipe the output through jq
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = bytes.NewReader(output)

	// Create file to write the formatted output
	file, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer file.Close()

	// Set the output of jq to the file
	jqCmd.Stdout = file

	// Run the jq command
	err = jqCmd.Run()
	if err != nil {
		return "", fmt.Errorf("failed to execute jq command: %w", err)
	}

	result := fmt.Sprintf("SLB information exported successfully to %s", outputFile)
	return result, nil
}

func main() {
	// Example usage
	result, err := QuerySLBAndExport("my-slb-name", "output.json")
	if err != nil {
		fmt.Printf("Error: %v\n", err)
	} else {
		fmt.Println(result)
	}
}

