package main

import (
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to query SLB information and exports it to a file
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the command to execute
	cmd := exec.Command("bash", "-c", 
		fmt.Sprintf("aliyun slb DescribeLoadBalancers --LoadBalancerName %s | jq '.LoadBalancers.LoadBalancer[]' > %s", 
			loadBalancerName, outputFile))

	// Execute the command
	output, err := cmd.CombinedOutput()
	if err != nil {
		return "", fmt.Errorf("command execution failed: %v, output: %s", err, string(output))
	}

	result := fmt.Sprintf("Successfully exported SLB info for '%s' to '%s'", loadBalancerName, outputFile)
	return result, nil
}

func main() {
	// Example usage
	result, err := QuerySLBAndExport("my-slb-name", "output.json")
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}
	fmt.Println(result)
}

